import { useEffect, useState } from 'react';
import api from '../../services/api';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export default function Dashboard() {
  const [productosBajoStock, setProductosBajoStock] = useState([]);
  const [ultimasVentas, setUltimasVentas] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [stockRes, ventasRes] = await Promise.all([
          api.get('/reportes/stock-bajo'),
          api.get('/ventas')
        ]);
        setProductosBajoStock(stockRes.data);
        setUltimasVentas(ventasRes.data.slice(0, 5));
      } catch (error) {
        toast.error('Error al cargar datos del dashboard');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) return <div className="text-center">Cargando...</div>;

  return (
    <div>
      <h1 className="text-2xl font-bold mb-6">Panel de Control</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-4 rounded shadow">
          <h2 className="text-xl font-semibold mb-3">Productos con stock bajo</h2>
          {productosBajoStock.length === 0 ? (
            <p>No hay productos con stock bajo.</p>
          ) : (
            <ul className="list-disc pl-5">
              {productosBajoStock.map(p => (
                <li key={p.id}>{p.nombre} - Stock: {p.stock_actual} (mínimo: {p.stock_minimo})</li>
              ))}
            </ul>
          )}
          <Link to="/productos" className="text-blue-600 text-sm mt-2 inline-block">Gestionar productos →</Link>
        </div>
        <div className="bg-white p-4 rounded shadow">
          <h2 className="text-xl font-semibold mb-3">Últimas ventas</h2>
          {ultimasVentas.length === 0 ? (
            <p>No hay ventas registradas.</p>
          ) : (
            <ul className="divide-y">
              {ultimasVentas.map(v => (
                <li key={v.id} className="py-2">
                  {v.cliente_nombre} - ${v.total} - {new Date(v.fecha).toLocaleDateString()}
                </li>
              ))}
            </ul>
          )}
          <Link to="/ventas" className="text-blue-600 text-sm mt-2 inline-block">Ver historial →</Link>
        </div>
      </div>
    </div>
  );
}
